// This method calculates the total outstanding amount of all invoices associated with a customer and sends a bill.
public double getTotalOutstandingAndSendBill() {
    double result = 0; // Initialize the result variable to store the sum of invoice amounts.

    for (Invoice each : customer.getInvoices()) { // Iterate through each invoice in the customer's list.
        result += each.getAmount(); // Add the amount of each invoice to the result.
    }

    sendBill(); // Call the method to send a bill with the calculated total outstanding amount.

    return result; // Return the total outstanding amount after sending the bill.
}
