public int calculateOrderTotal(String orderString, List<String> priceList) {
    // Split the order string by spaces to get individual parts of the order data.
    String[] orderData = orderString.split("\\s+");

    // Split the first part of the order data (before the dash) by dashes to extract product details.
    String[] productDetails = orderData[0].split("–");

    // Retrieve the price for the specified product from the predefined list using the product code.
    int productPrice = priceList.get(productDetails[1]);

    // Calculate the total price of the order by multiplying the quantity (extracted from the second part of the order data) with the product price.
    int orderPrice = Integer.parseInt(orderData[1]) * productPrice;

    return orderPrice; // Return the calculated total price.
}
