    // Constructor for initializing an empty stack
    public Stack() {
        super(); // Call the constructor of the superclass (List)
    }

    // Method to push an element onto the stack
    public void push(Object item) {
        // Add the item to the end of the list
        add(item);
    }

    // Method to pop an element from the stack
    public Object pop() {
        // Remove and return the last element in the list (top of the stack)
        if (!isEmpty()) {
            return remove(size() - 1);
        } else {
            throw new EmptyStackException("Stack is empty");
        }
    }

    // Method to check if the stack is empty
    public boolean isEmpty() {
        // Return true if the size of the list is zero, indicating an empty stack
        return size() == 0;
    }
}
