// This method calculates the final score for a candidate based on their performance in a medical exam and a scoring guide.
public int score(Candidate candidate, MedicalExam medicalExam, ScoringGuide scoringGuide) {
    int result = 0;
    int healthLevel = 0;

    // Calculate the health level based on the candidate's physical condition
    if (medicalExam.getHealthStatus() == HealthStatus.EXCELLENT) {
        healthLevel = 10; // Excellent health status gives a high score
    } else if (medicalExam.getHealthStatus() == HealthStatus.GOOD) {
        healthLevel = 8; // Good health status gives a moderate score
    } else {
        healthLevel = 6; // Poor health status gives a low score
    }

    // Calculate the result based on the candidate's performance and the scoring guide
    if (medicalExam.getPerformance() >= scoringGuide.getMinPerformance()) {
        result += healthLevel * scoringGuide.getMaxScore();
    } else {
        result += healthLevel * scoringGuide.getMinScore();
    }

    return result;
}
```

